const FMP_API_KEY = "rGc2qRoAlMqsUrJnOzkesp4U6qppd63a";
const FMP_BASE    = "https://financialmodelingprep.com";

// Rate limiter ГғВўГӮВҖГӮВ” free tier: 250 calls/day, ~10/min safe
const callQueue = [];
let lastCall = 0;
async function fmpFetch(endpoint, params = {}) {
  const query = new URLSearchParams({ ...params, apikey: FMP_API_KEY }).toString();
  const url = `${FMP_BASE}${endpoint}?${query}`;
  const now = Date.now();
  const gap = now - lastCall;
  if (gap < 300) await new Promise(r => setTimeout(r, 300 - gap)); // throttle
  lastCall = Date.now();
  const res = await fetch(url);
  if (!res.ok) throw new Error(`FMP ${res.status}: ${endpoint}`);
  const data = await res.json();
  // Detect FMP free-tier limit responses
  if (data && !Array.isArray(data)) {
    const msg = data["Error Message"] || data.message || "";
    if (typeof msg === "string" && (msg.toLowerCase().includes("limit") || msg.toLowerCase().includes("exclusive"))) {
      throw new Error(`FMP_LIMIT_REACHED`);
    }
  }
  return data;
}

// ГғВўГӮВ”ГӮВҖГғВўГӮВ”ГӮВҖ Company search ГғВўГӮВ”ГӮВҖГғВўГӮВ”ГӮВҖ
async function searchCompanies(query) {
  if (!query || query.length < 1) return [];
  const data = await fmpFetch("/stable/search-symbol", { query, limit: 10 });
  return Array.isArray(data) ? data : [];
}

