function useAuth() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    try { const s = sessionStorage.getItem("aramis_v6"); if (s) setUser(JSON.parse(s)); } catch {}
    setLoading(false);
  }, []);
  const login = (email, password) => {
    const u = USERS.find(x => x.email.toLowerCase() === email.toLowerCase() && x.password === password);
    if (!u) return { error: "Invalid credentials." };
    const s = { ...u, password: undefined, loginTime: new Date().toISOString() };
    sessionStorage.setItem("aramis_v6", JSON.stringify(s));
    setUser(s);
    return { success: true };
  };
  const logout = () => { sessionStorage.removeItem("aramis_v6"); setUser(null); };
  return { user, loading, login, logout, permissions: user ? PERMS[user.tier] : null };
}

