function DisciplineRadar({ scores, size=195 }) {
  const axes=[{key:"valuation",label:"Valuation"},{key:"growth",label:"Growth"},{key:"health",label:"Health"},{key:"moat",label:"Moat"},{key:"africa",label:"Africa Risk"},{key:"governance",label:"Governance"}];
  const n=axes.length,cx=size/2,cy=size/2,r=size*0.33,step=(2*Math.PI)/n;
  const pt=(i,v)=>{const a=i*step-Math.PI/2,d=(v/100)*r;return{x:cx+d*Math.cos(a),y:cy+d*Math.sin(a)};};
  const avg=Math.round(Object.values(scores).reduce((a,b)=>a+b,0)/n);
  const col=avg>=80?"#22c55e":avg>=60?GOLD:avg>=40?"#f59e0b":"#ef4444";
  const pts=axes.map((a,i)=>pt(i,scores[a.key]||0));
  const d=pts.map((p,i)=>`${i===0?"M":"L"}${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(" ")+" Z";
  return (
    <div style={{display:"flex",flexDirection:"column",alignItems:"center"}}>
      <svg width={size} height={size} style={{overflow:"visible"}}>
        {[20,40,60,80,100].map(l=>{const ps=axes.map((_,i)=>pt(i,l));const pd=ps.map((q,i)=>`${i===0?"M":"L"}${q.x.toFixed(1)},${q.y.toFixed(1)}`).join(" ")+" Z";return<path key={l} d={pd} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="1"/>;})
        }
        {axes.map((_,i)=>{const p=pt(i,100);return<line key={i} x1={cx} y1={cy} x2={p.x} y2={p.y} stroke="rgba(255,255,255,0.06)" strokeWidth="1"/>;})
        }
        <path d={d} fill={col+"20"} stroke={col} strokeWidth="1.5"/>
        {pts.map((p,i)=><circle key={i} cx={p.x} cy={p.y} r="2.5" fill={col}/>)}
        {axes.map((a,i)=>{const ang=i*step-Math.PI/2,ld=r+22,lx=cx+ld*Math.cos(ang),ly=cy+ld*Math.sin(ang);return<text key={i} x={lx} y={ly} textAnchor="middle" dominantBaseline="middle" fill="rgba(255,255,255,0.35)" fontSize="8.5" fontFamily="DM Mono,monospace">{a.label}</text>;})}
        <text x={cx} y={cy-9} textAnchor="middle" fill={col} fontSize="20" fontWeight="700" fontFamily="Syne,sans-serif">{avg}</text>
        <text x={cx} y={cy+11} textAnchor="middle" fill="rgba(255,255,255,0.25)" fontSize="6.5" fontFamily="DM Mono,monospace">DISCIPLINE SCOREГғВўГӮВ„ГӮВў</text>
      </svg>
    </div>
  );
}

